export default function TablaResultados({ datos }) {
  if (!datos.length) return <p>No hay datos aún.</p>;

  const columnas = Object.keys(datos[0]);

  return (
    <table border="1" cellPadding="5" style={{ borderCollapse: "collapse", width: "100%" }}>
      <thead>
        <tr>
          {columnas.map((col) => (
            <th key={col}>{col}</th>
          ))}
        </tr>
      </thead>
      <tbody>
        {datos.map((fila, i) => (
          <tr key={i}>
            {columnas.map((col) => (
              <td key={col}>{fila[col]}</td>
            ))}
          </tr>
        ))}
      </tbody>
    </table>
  );
}
